import time
import can
import pytest

GW_BRAKE_WARNING_ID = 0x110
GW_BRAKE_WARNING_DLC = 8

@pytest.fixture(scope="module")
def can_bus():
    bus = can.Bus(interface="vector", channel=0, bitrate=500000)
    yield bus
    bus.shutdown()

def collect_messages(bus, msg_id, duration_sec):
    messages = []
    start_time = time.time()
    while time.time() - start_time < duration_sec:
        msg = bus.recv(timeout=0.5)
        if msg and msg.arbitration_id == msg_id:
            messages.append(msg)
    return messages

def decode_brake_warning(msg):
    return (msg.data[0] >> 0) & 0x01

test_cases.python_test_script:
def test_tc_gw_brk_001_message_present(can_bus):
    msgs = collect_messages(can_bus, GW_BRAKE_WARNING_ID, 2)
    assert msgs, 'GW_BrakeWarning message not received'

def test_tc_gw_brk_002_inactive_state(can_bus):
    msgs = collect_messages(can_bus, GW_BRAKE_WARNING_ID, 2)
    assert msgs, 'No GW_BrakeWarning messages received'
    for msg in msgs:
        assert decode_brake_warning(msg) == 0

def test_tc_gw_brk_003_active_state(can_bus):
    msgs = collect_messages(can_bus, GW_BRAKE_WARNING_ID, 2)
    assert msgs, 'No GW_BrakeWarning messages received'
    for msg in msgs:
        assert decode_brake_warning(msg) == 1

def test_tc_gw_brk_004_deactivation(can_bus):
    msgs = collect_messages(can_bus, GW_BRAKE_WARNING_ID, 2)
    assert msgs, 'No GW_BrakeWarning messages received'
    for msg in msgs:
        assert decode_brake_warning(msg) == 0

def test_tc_gw_brk_005_no_unintended_toggle(can_bus):
    msgs = collect_messages(can_bus, GW_BRAKE_WARNING_ID, 3)
    assert msgs, 'No GW_BrakeWarning messages received'
    first = decode_brake_warning(msgs[0])
    for msg in msgs:
        assert decode_brake_warning(msg) == first

def test_tc_gw_brk_006_dlc_check(can_bus):
    msgs = collect_messages(can_bus, GW_BRAKE_WARNING_ID, 2)
    assert msgs, 'No GW_BrakeWarning messages received'
    for msg in msgs:
        assert msg.dlc == GW_BRAKE_WARNING_DLC
